/* /accounting/advisory/faq/ — t-guide CollectionPage + FAQPage elevation
 * (MIGRATION-PROTOCOL, content-to-goal / visual-floor). Migrated from
 * accounting/advisory/faq/index.html (old kb-* knowledge base) onto the cobalt
 * t-guide tier. FROZEN CONTRACT (contract-acct-adv-faq.txt) is the only authority
 * for the 25 headings + the 7 FAQ; old HTML read for BODY PROSE only.
 *
 * Pattern carried VERBATIM from the proven sibling src/accounting/bookkeeping/faq.njk
 * + .11tydata.js (and src/quickbooks/faq.njk, src/partners/faq.njk): guide-grid
 * (sticky toc + article.prose) · byline-block · pull-quote · meta-reviewed. The 7
 * cluster H2s become article <h2> sections, EACH carrying its real advisory-FAQ
 * prose — every Q/A from the old kb-cluster bodies survives as an in-cluster
 * <h3> + answer (content elevation, no gutting). The old HTML carried 38 body Q/A
 * across the same 7 clusters (q01–q38); all 38 are preserved here as cluster items.
 * The 7 contract FAQ render as a faq__list AND regenerate the FAQPage from the SAME
 * array (schema == rendered, verbatim/flat, append-only).
 *
 * Parent hub: src/accounting/advisory.njk. CTA lexicon (canonical only):
 * "Book the discovery call" -> /contact/?intent=advisory; "Get the free file
 * review" -> /quickbooks/file-review/?intent=file-review; "Speak to a ProAdvisor"
 * (tel). HONESTY (R5/R9): firm-level byline (Certified QuickBooks ProAdvisor team,
 * never an individual); independent firm, not affiliated with Intuit Inc.; advisory
 * is operational + strategic finance, NOT tax filing/audit (CPA work) — boundary
 * held; no fabricated stats/outcomes/reviews; no AggregateRating; no Clutch.
 *
 * ANCHORS: every old body question keeps a stable in-page anchor advfaq-q01..q38.
 * The 6-question popular strip points at the real item anchors that exist (fixing
 * the prior #faq-q1..#faq-q6 dead links). */
function stripTags(html){return html.replace(/<[^>]+>/g," ").replace(/&rsquo;/g,"’").replace(/&lsquo;/g,"‘").replace(/&ldquo;/g,"“").replace(/&rdquo;/g,"”").replace(/&mdash;/g,"—").replace(/&ndash;/g,"–").replace(/&rarr;/g,"→").replace(/&amp;/g,"&").replace(/&nbsp;/g," ").replace(/&middot;/g,"·").replace(/&divide;/g,"÷").replace(/&times;/g,"×").replace(/&hellip;/g,"…").replace(/\s+/g," ").trim();}

